import { useState } from "react";

export default function NestedLists() {
  return (
    <>
      {/* SPRITE */}
      <svg style={{ display: "none" }}>
        <symbol id="icon-expand" viewBox="0 -960 960 960">
          <path d="M480-372.92q-7.23 0-13.46-2.31t-11.85-7.92L274.92-562.92q-8.3-8.31-8.5-20.89-.19-12.57 8.5-21.27 8.7-8.69 
          21.08-8.69t21.08 8.69L480-442.15l162.92-162.93q8.31-8.3 20.89-8.5 12.57-.19 21.27 8.5 8.69 8.7 8.69 
          21.08t-8.69 21.08L505.31-383.15q-5.62 5.61-11.85 7.92T480-372.92"></path>
        </symbol>

        <symbol id="icon-plus" viewBox="0 -960 960 960">
          <path
            d="M480 -720 L480 -240 M240 -480 L720 -480"
            stroke="currentColor"
            strokeWidth="88"
            strokeLinecap="round"
            strokeLinejoin="round"
            fill="none"
          />
        </symbol>
      </svg>

      <List type="root" title="Главный список" />
    </>
  );
}

function List({ type, title }) {
  const [expanded, setExpanded] = useState(true);
  const [children, setChildren] = useState([]);
  const [fields, setFields] = useState([]);

  const addChildList = () => {
    setChildren(prev => [
      ...prev,
      { id: crypto.randomUUID() }
    ]);
  };

  const addField = () => {
    setFields(prev => [
      ...prev,
      { id: crypto.randomUUID(), value: "" }
    ]);
  };

  const updateField = (id, text) => {
    setFields(prev =>
      prev.map(f => (f.id === id ? { ...f, value: text } : f))
    );
  };

  const deleteField = (id) => {
    setFields(prev => prev.filter(f => f.id !== id));
  };

  return (
    <div style={{ border: "1px solid #aaa", padding: 10, margin: 10 }}>
      {/* HEADER */}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        {/* Toggle arrow */}
        <svg
          style={{
            width: 20,
            height: 20,
            cursor: "pointer",
            transform: expanded ? "rotate(180deg)" : "rotate(0deg)",
            transition: "0.2s"
          }}
          onClick={() => setExpanded(!expanded)}
        >
          <use href="#icon-expand" />
        </svg>

        {type === "root" ? (
          <h2 style={{ margin: 0 }}>{title}</h2>
        ) : (
          <input
            placeholder="Название списка"
            style={{ fontSize: 18 }}
          />
        )}

        {/* PLUS button */}
        <svg
          style={{ width: 20, height: 20, cursor: "pointer" }}
          onClick={() => {
            if (type === "root") addChildList();
            else addField();
          }}
        >
          <use href="#icon-plus" />
        </svg>
      </div>

      {/* CONTENT */}
      {expanded && (
        <div style={{ marginLeft: 25, marginTop: 10 }}>
          {/* FIELDS only for CHILD */}
          {type === "child" &&
            fields.map(field => (
              <div
                key={field.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                  marginBottom: 6
                }}
              >
                <input
                  value={field.value}
                  onChange={(e) => updateField(field.id, e.target.value)}
                />
                <span
                  style={{ color: "red", cursor: "pointer" }}
                  onClick={() => deleteField(field.id)}
                >
                  Удалить
                </span>
              </div>
            ))}

          {/* CHILD LISTS */}
          {children.map(ch => (
            <List key={ch.id} type="child" />
          ))}
        </div>
      )}
    </div>
  );
}
